sql:
SELECT step_description 
FROM reaction_steps 
WHERE reaction_id = 1;

SELECT reaction_type, COUNT(DISTINCT pathway_id) AS num_pathways
FROM reactions
GROUP BY reaction_type;

SELECT step_id, step_number, step_description, conditions, reactants, products, catalyst, is_reversible, rate_constant, activation_energy
FROM reaction_steps
WHERE reaction_id = 1 AND step_number = 1;

SELECT * 
FROM reactants 
WHERE reactant_id = 1;

SELECT reaction_name, reaction_number, AVG(equilibrium_constant) AS avg_equilibrium_constant
FROM reactions
GROUP BY reaction_type;

SELECT DISTINCT p.product_name
FROM products p
JOIN reaction_steps rs ON rs.products LIKE '%' || p.product_name || '%';

SELECT r.reaction_name, r.description, r.status
FROM reactions r
JOIN reaction_steps rs ON r.reaction_id = rs.reaction_id
WHERE rs.rate_constant > (
    SELECT AVG(rate_constant) FROM reaction_steps
);
